content:
Imagine a simple interaction:

Click → animate button → fetch users → render results → highlight the first result

The user experiences these steps in a clear sequence. But does the code describe that sequence just as clearly? Can a single state hold not just a final value, but the transition like the button's animation that leads to it?

React

Here is one way to implement this interaction in React without using an animation library:

import { useState } from "react";
export default function UserSearch() {
const [users, setUsers] = useState([]);
const [isSearching, setIsSearching] = useState(false);
const [isAnimating, setIsAnimating] = useState(false);
const [highlightFirst, setHighlightFirst] = useState(false);
async function handleSearch() {
if (isSearching) return;
setIsSearching(true);
setUsers([]);
setHighlightFirst(false);
// Animate the button.
setIsAnimating(true);
// Fetch users.
const response = await fetch(
"https://targetjs.io/api/randomUsers"
);
const newUsers = await response.json();
setIsAnimating(false);
// Render the results.
setUsers(newUsers);
// Wait for the new UI to appear.
await new Promise(resolve => {
setTimeout(resolve, 150);
});
// Highlight the first result.
setHighlightFirst(true);
setIsSearching(false);
}
return (
<div className="search">
<button
className={
isAnimating
? "search-button active"
: "search-button"
}
disabled={isSearching}
onClick={handleSearch}
>
{isSearching ? "Searching..." : "Search"}
</button>
<div className="users">
{users.map((user, index) => (
<div
className={
index === 0 && highlightFirst
? "user highlighted"
: "user"
}
key={user.email}
>
<strong>{user.name}</strong>
<span>{user.email}</span>
</div>
))}
</div>
</div>
);
}

